#include <stdio.h>
#include <semaphore.h>

int sem_counter(sem_t *s) {
    int val;
    if (sem_getvalue(s, &val) != 0) return -1;
    return val;
}

int sem_down_n(sem_t *s, int n) {
    for (int i = 0; i < n; i++) {
        if (sem_wait(s) != 0) return -1;
    }
    return 0;
}

int sem_up_n(sem_t *s, int n) {
    for (int i = 0; i < n; i++) {
        if (sem_post(s) != 0) return -1;
    }
    return 0;
}

int main(void) {
    {
        sem_t s;
        sem_init(&s, 0, 3);
        printf("%d\n", (int)(sem_counter(&s)));
        sem_destroy(&s);
    }
    {
        sem_t s;
        sem_init(&s, 0, 0);
        printf("%d\n", (int)(sem_up_n(&s, 4)));
        printf("%d\n", (int)(sem_counter(&s)));
        sem_destroy(&s);
    }
    {
        sem_t s;
        sem_init(&s, 0, 5);
        printf("%d\n", (int)(sem_down_n(&s, 3)));
        printf("%d\n", (int)(sem_counter(&s)));
        sem_destroy(&s);
    }
    {
        sem_t s;
        sem_init(&s, 0, 0);
        sem_up_n(&s, 6);
        sem_down_n(&s, 6);
        printf("%d\n", (int)(sem_counter(&s)));
        sem_destroy(&s);
    }
    {
        sem_t s;
        sem_init(&s, 0, 1);
        sem_post(&s);
        sem_post(&s);
        printf("%d\n", (int)(sem_counter(&s)));
        sem_destroy(&s);
    }
    return 0;
}
